import{_ as t,o,c as r,ag as a}from"./chunks/framework.BYehg5q7.js";const m=JSON.parse('{"title":"AI Providers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai-providers.md","filePath":"guide/ai-providers.md","lastUpdated":1772692870000}'),i={name:"guide/ai-providers.md"};function s(l,e,n,d,c,p){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="ai-providers" tabindex="-1">AI Providers <a class="header-anchor" href="#ai-providers" aria-label="Permalink to &quot;AI Providers&quot;">​</a></h1><p>getbased supports four AI backends for PDF import, chat, and dashboard AI features. You can switch between them at any time in <strong>Settings → AI</strong>.</p><h2 id="which-features-need-an-ai-provider" tabindex="-1">Which Features Need an AI Provider? <a class="header-anchor" href="#which-features-need-an-ai-provider" aria-label="Permalink to &quot;Which Features Need an AI Provider?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Requires AI?</th></tr></thead><tbody><tr><td>PDF import</td><td>Yes</td></tr><tr><td>AI chat panel</td><td>Yes</td></tr><tr><td>Focus card (dashboard insight)</td><td>Yes</td></tr><tr><td>Health status dots on context cards</td><td>Yes</td></tr><tr><td>AI-generated card tips</td><td>Yes</td></tr><tr><td>Charts, tables, trend alerts</td><td>No</td></tr><tr><td>Manual entry</td><td>No</td></tr><tr><td>JSON export / import</td><td>No</td></tr><tr><td>Correlations, compare dates</td><td>No</td></tr><tr><td>Marker glossary</td><td>No</td></tr></tbody></table><p>All non-AI features work fully without any provider configured.</p><h2 id="the-four-providers" tabindex="-1">The Four Providers <a class="header-anchor" href="#the-four-providers" aria-label="Permalink to &quot;The Four Providers&quot;">​</a></h2><h3 id="openrouter-recommended" tabindex="-1">OpenRouter (Recommended) <a class="header-anchor" href="#openrouter-recommended" aria-label="Permalink to &quot;OpenRouter (Recommended)&quot;">​</a></h3><p>A model marketplace that gives you access to 200+ models — Claude, GPT, Gemini, DeepSeek, Grok, Qwen, and more — through a single account. getbased shows a curated list of the latest medically capable models and displays live pricing for each. OpenRouter is the recommended provider and appears as the first tab in Settings.</p><p><strong>Setup — OAuth (easiest):</strong></p><ol><li>In Settings → AI Provider, select <strong>OpenRouter</strong></li><li>Click <strong>Connect with OpenRouter</strong></li><li>Authorize getbased on the OpenRouter site</li><li>You&#39;re connected — no API key needed</li></ol><p><strong>Setup — API key:</strong></p><ol><li>Get an API key at <a href="https://openrouter.ai" target="_blank" rel="noreferrer">openrouter.ai</a></li><li>In Settings → AI Provider, select <strong>OpenRouter</strong></li><li>Paste your API key</li><li>Choose a model from the curated dropdown</li></ol><div class="tip custom-block"><p class="custom-block-title">One-click connect</p><p>The OAuth button also appears in the chat setup guide when no provider is configured, making it easy for new users to get started.</p></div><h3 id="anthropic" tabindex="-1">Anthropic <a class="header-anchor" href="#anthropic" aria-label="Permalink to &quot;Anthropic&quot;">​</a></h3><p>Direct access to Claude models via the Anthropic API. Claude was specifically designed to be helpful with medical and scientific information, making it an accurate choice for interpreting lab data.</p><p><strong>Setup:</strong></p><ol><li>Get an API key at <a href="https://console.anthropic.com" target="_blank" rel="noreferrer">console.anthropic.com</a></li><li>In Settings → AI Provider, select <strong>Anthropic</strong></li><li>Paste your API key</li><li>Choose a model from the dropdown (the app fetches available models automatically)</li></ol><div class="tip custom-block"><p class="custom-block-title">Pay per use</p><p>Anthropic charges per token. A typical PDF import costs a few cents. Chat responses cost fractions of a cent each.</p></div><h3 id="venice-ai-best-for-privacy" tabindex="-1">Venice AI (Best for privacy) <a class="header-anchor" href="#venice-ai-best-for-privacy" aria-label="Permalink to &quot;Venice AI (Best for privacy)&quot;">​</a></h3><p>A privacy-focused cloud provider where your conversations and data are not stored or logged on their servers. Venice also proxies access to GPT, Grok, and DeepSeek models.</p><p><strong>Setup:</strong></p><ol><li>Get an API key at <a href="https://venice.ai" target="_blank" rel="noreferrer">venice.ai</a></li><li>In Settings → AI Provider, select <strong>Venice</strong></li><li>Paste your API key</li><li>Choose a model from the dropdown</li></ol><h3 id="local-ai-fully-local" tabindex="-1">Local AI (Fully local) <a class="header-anchor" href="#local-ai-fully-local" aria-label="Permalink to &quot;Local AI (Fully local)&quot;">​</a></h3><p>Run a language model entirely on your own machine. Nothing is sent over the network — not even for PDF import. Local AI connects via the standard OpenAI-compatible API (<code>/v1/chat/completions</code>), which is supported by all major local servers:</p><ul><li><a href="https://ollama.com" target="_blank" rel="noreferrer">Ollama</a> — easiest setup, pull models from the command line</li><li><a href="https://lmstudio.ai" target="_blank" rel="noreferrer">LM Studio</a> — GUI-based, drag-and-drop model loading</li><li><a href="https://jan.ai" target="_blank" rel="noreferrer">Jan</a> — open-source desktop app</li><li>llama.cpp, LocalAI, and others</li></ul><p><strong>Setup:</strong></p><ol><li>Install and start any local AI server</li><li>Load a model (e.g., in Ollama: <code>ollama pull llama3.2</code>)</li><li>In Settings → AI Provider, select <strong>Local</strong></li><li>Enter your server URL (default: <code>http://localhost:11434</code>)</li><li>Click <strong>Test</strong> — the app auto-discovers available models</li><li>Add an API key if your server requires one (most don&#39;t)</li></ol><div class="tip custom-block"><p class="custom-block-title">Local AI also handles PII stripping</p><p>When enabled in Settings → Privacy, your local server is used to intelligently strip personal information from PDFs before analysis. See <a href="./pii-obfuscation.html">PII Obfuscation</a> for details.</p></div><div class="tip custom-block"><p class="custom-block-title">Accessing from another device on your network</p><p>To connect from a different computer on your local network, set the appropriate environment variables on the server machine. For Ollama: <code>OLLAMA_HOST=0.0.0.0 OLLAMA_ORIGINS=* ollama serve</code>, then use <code>http://&lt;server-ip&gt;:11434</code> as the server URL. LM Studio and Jan have similar settings in their UI.</p></div><div class="warning custom-block"><p class="custom-block-title">Use a capable model</p><p>Smaller models (under ~7B parameters) may struggle with accurate marker extraction from complex lab PDFs. A 13B+ model is recommended for best results.</p></div><h2 id="recommended-models" tabindex="-1">Recommended Models <a class="header-anchor" href="#recommended-models" aria-label="Permalink to &quot;Recommended Models&quot;">​</a></h2><p>All providers show a tiered model dropdown with two groups:</p><ul><li><strong>★ Recommended</strong> — the latest, most capable models for lab interpretation (sorted first)</li><li><strong>Other</strong> — all remaining available models</li></ul><p>Recommended models are chosen for accuracy with medical/scientific data. You can use any model, but recommended ones produce the most reliable results.</p><h2 id="model-consistency" tabindex="-1">Model Consistency <a class="header-anchor" href="#model-consistency" aria-label="Permalink to &quot;Model Consistency&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Use the same model across imports</p><p>When you import lab PDFs, the AI generates marker keys (like <code>biochemistry.glucose</code>) to map results. Different models may generate slightly different keys for the same marker. Switching models between imports can cause the same marker to appear as two separate entries.</p><p>For best results, pick a model and stick with it for all your imports. If you do switch, getbased runs a pre-flight check before each import and warns you if your model has changed since the last import.</p></div><h2 id="switching-providers" tabindex="-1">Switching Providers <a class="header-anchor" href="#switching-providers" aria-label="Permalink to &quot;Switching Providers&quot;">​</a></h2><p>You can switch providers at any time in Settings without losing any data. Your API keys are stored locally in your browser and are never sent to getbased servers.</p>',38)])])}const u=t(i,[["render",s]]);export{m as __pageData,u as default};
